function first<T>(arr: T[]): T | undefined {
  return arr[0];
}

const n = first([1, 2, 3]);   // inferido: number | undefined
const s = first(['a', 'b']); // inferido: string | undefined

function getLabel<T extends { label: string }>(item: T): string {
  return item.label; // seguro — T debe tener label
}

type EsString<T> = T extends string ? true : false;

type A = EsString<string>; // true
type B = EsString<number>; // false

// server/routers/user.ts
import { z } from 'zod';
import { router, publicProcedure } from '../trpc';
import { prisma } from '../db';

export const userRouter = router({
  byId: publicProcedure
    .input(z.object({ id: z.string().cuid() }))
    .query(({ input }) => prisma.user.findUnique({ where: { id: input.id } })),
});
